export function getStateBySlug(slug: string): StateData | undefined {
  return STATES[slug];
}

export function getStatesByRegion(region: Region | string): StateData[] {
  return Object.values(STATES).filter((state) => state.region === region);
}

export function getAllCitySlugs(): string[] {
  const slugs: string[] = [];
  Object.values(STATES).forEach((state) => {
    state.topCities.forEach((city) => {
      slugs.push(city.slug);
    });
  });
  return slugs;
}

export const STATE_SLUGS = Object.keys(STATES);
